function SpinningLogo() {
  return (
    <div className="spinning-logo">
      <svg viewBox="0 0 32 32" fill="none" width="32" height="32">
        <circle cx="16" cy="16" r="14" stroke="#2d6fc4" strokeWidth="1.3" opacity="0.5" strokeDasharray="18 8" />
        <circle cx="16" cy="16" r="8"  stroke="#5baee0" strokeWidth="0.9" opacity="0.4" strokeDasharray="10 6" />
        {[0, 60, 120, 180, 240, 300].map((a, i) => {
          const rad = (Math.PI * a) / 180;
          return (
            <line
              key={i}
              x1={16 + 8  * Math.cos(rad)} y1={16 + 8  * Math.sin(rad)}
              x2={16 + 13 * Math.cos(rad)} y2={16 + 13 * Math.sin(rad)}
              stroke="#5baee0" strokeWidth="1.2" opacity="0.6"
            />
          );
        })}
        <circle cx="16" cy="16" r="3" fill="#2d6fc4" />
      </svg>
    </div>
  );
}

const BOT_LOGO_URI = "data:image/jpeg;base64,";

function BotAvatar() {
  return (
    <div className="msg__avatar">
      <img src={BOT_LOGO_URI} alt="Bot" style={{ width: 22, height: 22, objectFit: 'contain', borderRadius: '50%' }} />
    </div>
  );
}

export function TypingIndicator() {
  return (
    <div className="msg-row msg-row--bot">
      <SpinningLogo />
      <div className="msg__bubble msg__bubble--bot" style={{ padding: "10px 14px" }}>
        <div className="typing-dots">
          {[0, 0.22, 0.44].map((delay, i) => (
            <span
              key={i}
              className="typing-dot"
              style={{ animation: `bounceDot 1s ${delay}s ease-in-out infinite` }}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

export default function Message({ msg, index }) {
  const isUser = msg.role === "user";
  return (
    <div
      className={`msg-row ${isUser ? "msg-row--user" : "msg-row--bot"}`}
      style={{ animationDelay: `${index * 0.04}s` }}
    >
      {!isUser && <BotAvatar />}
      <div className={`msg__bubble ${isUser ? "msg__bubble--user" : "msg__bubble--bot"}`}>
        <div className="msg__text">{msg.text}</div>
        <div className="msg__meta">
          {msg.time}
          {isUser && <span className="msg__ticks">✓✓</span>}
        </div>
      </div>
    </div>
  );
}
